from dataclasses import dataclass, field
from typing import List, Optional
import datetime

@dataclass
class RateCardVersion:
    version_id: str                   # e.g. "2026-Q3"
    effective_date: str               # ISO date
    end_date: Optional[str]           # None if currently active
    rates: dict                       # model_id → {input, output, cache_read}

@dataclass
class RateCardRegistry:
    versions: List[RateCardVersion] = field(default_factory=list)

    def add_version(self, version: RateCardVersion) -> None:
        # Close the current active version
        for v in self.versions:
            if v.end_date is None and v.version_id != version.version_id:
                v.end_date = version.effective_date
        self.versions.append(version)

    def active_version(self) -> Optional[RateCardVersion]:
        today = datetime.date.today().isoformat()
        for v in self.versions:
            if v.effective_date <= today and v.end_date is None:
                return v
        return None

    def version_at_date(self, date_str: str) -> Optional[RateCardVersion]:
        """Find the rate card version that was active on a given date."""
        for v in sorted(self.versions, key=lambda x: x.effective_date, reverse=True):
            if v.effective_date <= date_str:
                return v
        return None

from dataclasses import dataclass

@dataclass
class InvoiceReconciliation:
    model_id: str
    period: str
    internal_rate_input_per_1m: float    # from rate card
    provider_invoice_total_usd: float    # actual provider charge for this model
    total_input_tokens: int
    total_output_tokens: int
    total_cache_tokens: int
    output_rate_per_1m: float
    cache_rate_per_1m: float

    @property
    def expected_provider_cost(self) -> float:
        return (self.total_input_tokens / 1_000_000 * self.internal_rate_input_per_1m
                + self.total_output_tokens / 1_000_000 * self.output_rate_per_1m
                + self.total_cache_tokens / 1_000_000 * self.cache_rate_per_1m)

    @property
    def variance_usd(self) -> float:
        return self.provider_invoice_total_usd - self.expected_provider_cost

    @property
    def variance_pct(self) -> float:
        if self.expected_provider_cost == 0:
            return 0.0
        return self.variance_usd / self.expected_provider_cost * 100

    def is_reconciled(self, tolerance_pct: float = 2.0) -> bool:
        return abs(self.variance_pct) <= tolerance_pct
